async (params, browser) => {
  // Open Wayback Machine
  await browser.open(`https://web.archive.org/web/${params.date}/${params.url}`)

  // Wait for page
  await browser.waitForSelector('body', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const title = document.title || ''; const text = document.body?.innerText?.slice(0, 2000) || ''; return { title, snapshot_date: '' + params.date + '', content_preview: text, url: window.location.href };`)

  return result
}
